class Solution:
    def maxHeight(self, cuboids):
        # Independent derivation: normalize, then order by TOTAL dimension sum
        # (elementwise <= always implies sum <=, so this is a different but still
        # valid topological order from the lexicographic sort used in the optimal
        # solution), and push each base FORWARD onto every later cuboid it can
        # support instead of pulling from earlier compatible bases.
        n = len(cuboids)
        norm = [tuple(sorted(c)) for c in cuboids]
        order = sorted(range(n), key=lambda idx: sum(norm[idx]))
        best = [norm[idx][2] for idx in order]
        for a in range(n):
            i = order[a]
            for b in range(a + 1, n):
                j = order[b]
                if norm[i][0] <= norm[j][0] and norm[i][1] <= norm[j][1] and norm[i][2] <= norm[j][2]:
                    candidate = best[a] + norm[j][2]
                    if candidate > best[b]:
                        best[b] = candidate
        return max(best) if best else 0

solutions.python:
class Solution:
    def maxHeight(self, cuboids: List[List[int]]) -> int:
        norm = sorted(sorted(c) for c in cuboids)
        n = len(norm)
        dp = [c[2] for c in norm]
        for i in range(n):
            for j in range(i):
                if norm[j][0] <= norm[i][0] and norm[j][1] <= norm[i][1] and norm[j][2] <= norm[i][2]:
                    dp[i] = max(dp[i], dp[j] + norm[i][2])
        return max(dp)

