var maxHeight = function(cuboids) {
    const norm = cuboids.map(c => c.slice().sort((a, b) => a - b));
    norm.sort((a, b) => a[0] - b[0] || a[1] - b[1] || a[2] - b[2]);
    const n = norm.length;
    const dp = norm.map(c => c[2]);
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < i; j++) {
            if (norm[j][0] <= norm[i][0] && norm[j][1] <= norm[i][1] && norm[j][2] <= norm[i][2]) {
                dp[i] = Math.max(dp[i], dp[j] + norm[i][2]);
            }
        }
    }
    return Math.max(...dp);
};
